    private static final java.util.Map<ProviderName, Spec> BY_NAME =
            new java.util.EnumMap<>(ProviderName.class);

    static {
        for (Spec spec : SPECS) {
            BY_NAME.put(spec.name, spec);
        }
    }

    /** Look up the internal wire spec for a provider identity. */
    public static Spec config(ProviderName name) {
        Spec spec = BY_NAME.get(name);
        if (spec == null) {
            throw new IllegalStateException("provider config missing from generated registry: " + name);
        }
        return spec;
    }
